#include <iostream>
#include <queue>
#include <sstream>
#include <string>
#include <vector>
using namespace std;struct Node{int val;vector<Node*>ch;Node(int v):val(v){}};void split(const string&s,vector<string>&t){string cur;for(char c:s){if(c==','){t.push_back(cur);cur.clear();}else cur+=c;}t.push_back(cur);}Node* parse(string s){if(s=="[]")return nullptr;vector<string>tok;split(s.substr(1,s.size()-2),tok);Node*root=new Node(stoi(tok[0]));queue<Node*>q;q.push(root);int i=1;if(i<tok.size()&&tok[i]=="null")i++;while(!q.empty()&&i<tok.size()){Node*p=q.front();q.pop();while(i<tok.size()&&tok[i]!="null"){Node*c=new Node(stoi(tok[i++]));p->ch.push_back(c);q.push(c);}if(i<tok.size()&&tok[i]=="null")i++;}return root;}void serD(Node*n,vector<string>&v){v.push_back(to_string(n->val));v.push_back(to_string(n->ch.size()));for(auto*c:n->ch)serD(c,v);}string ser(Node*r){vector<string>v;if(r)serD(r,v);string out;for(int i=0;i<v.size();i++){if(i)out+=' ';out+=v[i];}return out;}Node* deD(vector<string>&v,int&i){Node*n=new Node(stoi(v[i++]));int cnt=stoi(v[i++]);while(cnt--)n->ch.push_back(deD(v,i));return n;}Node* de(string data){if(data.empty())return nullptr;stringstream ss(data);vector<string>v;string x;while(ss>>x)v.push_back(x);int i=0;return deD(v,i);}string fmt(Node*r){if(!r)return"[]";vector<string>out{to_string(r->val),"null"};queue<Node*>q;q.push(r);while(!q.empty()){Node*p=q.front();q.pop();for(auto*c:p->ch){out.push_back(to_string(c->val));q.push(c);}out.push_back("null");}while(!out.empty()&&out.back()=="null")out.pop_back();string s="[";for(int i=0;i<out.size();i++){if(i)s+=",";s+=out[i];}return s+"]";}int main(){ios::sync_with_stdio(false);cin.tie(nullptr);int t;string line;if(!(cin>>t))return 0;for(int i=0;i<t;i++){cin>>line;if(i)cout<<"\n\n";cout<<fmt(de(ser(parse(line))));}}
